package main

import (
	"database/sql"
	"flag"
	"fmt"
	"net/http"
	"os"

	"github.com/deepmap/oapi-codegen/pkg/middleware"
	_ "github.com/go-sql-driver/mysql"
	"github.com/labstack/echo/v4"
	echomiddleware "github.com/labstack/echo/v4/middleware"
	_ "github.com/mattn/go-sqlite3"

	"github.com/evgeniy-klemin/todo"
	"github.com/evgeniy-klemin/todo/db/driver"
	"github.com/evgeniy-klemin/todo/db/fts"
	"github.com/evgeniy-klemin/todo/db/migrations"
	item "github.com/evgeniy-klemin/todo/internal/item"
	itemports "github.com/evgeniy-klemin/todo/internal/item/ports"
)

func registerDoc(e *echo.Echo) {
	assetHandler := http.FileServer(todo.GetFileSystem())
	e.GET("/docs/*", echo.WrapHandler(http.StripPrefix("/docs/", assetHandler)))
	e.Use(func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			if c.Path() == "/" {
				_ = c.Redirect(http.StatusPermanentRedirect, "/docs/")
			}
			return next(c)
		}
	})
}

func setOapiValidator(e *echo.Echo) {
	itemSwagger, err := itemports.GetSwagger()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error loading swagger spec\n: %s", err)
		os.Exit(1)
	}
	itemSwagger.Servers = nil
	e.Use(middleware.OapiRequestValidatorWithOptions(itemSwagger, &middleware.Options{
		Skipper: func(c echo.Context) bool {
			switch c.Path() {
			case "/docs/*", "/":
				return true
			}
			return false
		},
	}))
}

func server(port int) {
	e := echo.New()
	// Log all requests
	e.Use(echomiddleware.Logger())
	// Swagger validation
	setOapiValidator(e)

	drv := os.Getenv("DB_DRIVER")
	if drv == "" {
		drv = driver.SQLite
	}

	dsn := os.Getenv("DB_DSN")
	if dsn == "" {
		switch drv {
		case driver.MySQL:
			dsn = "todo:todo@tcp(localhost)/todotest?parseTime=true"
		default:
			dsn = "file:todotest.db?cache=shared"
		}
	}

	db, err := sql.Open(drv, dsn)
	if err != nil {
		panic(err)
	}
	if err := migrations.Run(db, drv); err != nil {
		panic(err)
	}
	var ftsEnabled bool
	if drv == driver.MySQL {
		ftsEnabled = true // FULLTEXT index created by goose migration 00003
	} else {
		ftsEnabled = fts.Apply(db)
	}
	if !ftsEnabled {
		switch drv {
		case driver.MySQL:
			fmt.Fprintf(os.Stderr, "Warning: MySQL FULLTEXT index not available, falling back to LIKE search\n")
		default:
			fmt.Fprintf(os.Stderr, "Warning: FTS5 not available, falling back to LIKE search\n")
		}
	}

	// Containers
	itemContainer := item.NewContainer(db, drv, ftsEnabled)

	// Register http handlers
	itemContainer.RegisterHandlers(e)

	registerDoc(e)

	e.Logger.Fatal(e.Start(fmt.Sprintf("0.0.0.0:%d", port)))
}

func main() {
	var port = flag.Int("port", 3000, "Port for test HTTP server")
	flag.Parse()

	server(*port)
}

package domain

import (
	"fmt"
	"time"
)

var (
	ErrNameLength    = fmt.Errorf("name has wrong size")
	ErrPositionValue = fmt.Errorf("position has wrong value")
	ErrNotFound      = fmt.Errorf("item not found")
)

const (
	NameMinLength = 1
	NameMaxLength = 1000
	PositionMin   = 1
)

// Name is a value object representing a validated item name.
type Name struct {
	value string
}

func NewName(value string) (Name, error) {
	if len(value) < NameMinLength {
		return Name{}, fmt.Errorf("%w: '%s' value less than min %d - got %d", ErrNameLength, value, NameMinLength, len(value))
	}
	if len(value) > NameMaxLength {
		return Name{}, fmt.Errorf("%w: '%s' value more than max %d - got %d", ErrNameLength, value, NameMaxLength, len(value))
	}
	return Name{value: value}, nil
}

func (n Name) String() string { return n.value }

// Position is a value object representing a validated item position.
type Position struct {
	value int
}

func NewPosition(value int) (Position, error) {
	if value < PositionMin {
		return Position{}, fmt.Errorf("%w: %d value less than min %d", ErrPositionValue, value, PositionMin)
	}
	return Position{value: value}, nil
}

func (p Position) Int() int { return p.value }

// Item is the aggregate root with private fields.
type Item struct {
	id        ModelID
	name      Name
	position  Position
	done      bool
	createdAt time.Time
}

// Getters
func (i *Item) ID() ModelID        { return i.id }
func (i *Item) Name() Name         { return i.name }
func (i *Item) Position() Position  { return i.position }
func (i *Item) Done() bool          { return i.done }
func (i *Item) CreatedAt() time.Time { return i.createdAt }

// NewItem creates a new Item with validation via value objects.
func NewItem(name string, position int) (*Item, error) {
	id, err := GenerateModelID()
	if err != nil {
		return nil, err
	}
	n, err := NewName(name)
	if err != nil {
		return nil, err
	}
	p, err := NewPosition(position)
	if err != nil {
		return nil, err
	}
	return &Item{
		id:        id,
		name:      n,
		position:  p,
		done:      false,
		createdAt: time.Now().Truncate(time.Second),
	}, nil
}

// ReconstituteItem recreates an Item from persistence without validation.
func ReconstituteItem(id ModelID, name string, position int, done bool, createdAt time.Time) *Item {
	return &Item{
		id:        id,
		name:      Name{value: name},
		position:  Position{value: position},
		done:      done,
		createdAt: createdAt,
	}
}

// Behavior methods

func (i *Item) Complete() {
	i.done = true
}

func (i *Item) Uncomplete() {
	i.done = false
}

func (i *Item) Rename(name string) error {
	n, err := NewName(name)
	if err != nil {
		return err
	}
	i.name = n
	return nil
}

func (i *Item) MoveTo(position int) error {
	p, err := NewPosition(position)
	if err != nil {
		return err
	}
	i.position = p
	return nil
}

package app

import (
	"context"
	"errors"
	"log/slog"

	"github.com/evgeniy-klemin/todo/internal/item/domain"
)

type ItemService struct {
	repo domain.Repository
}

func NewItemService(repo domain.Repository) *ItemService {
	return &ItemService{
		repo: repo,
	}
}

func (s *ItemService) GetItemByID(ctx context.Context, id string) (*Item, error) {
	modelID, err := domain.NewModelID(id)
	if err != nil {
		return nil, Validation("get item by id", err)
	}
	item, err := s.repo.GetByID(ctx, modelID)
	if err != nil {
		if errors.Is(err, domain.ErrNotFound) {
			return nil, NotFound("get item by id", err)
		}
		return nil, err
	}
	return domainToAppItem(item, nil), nil
}

func (s *ItemService) Create(ctx context.Context, name string, position *int) (*Item, error) {
	if position != nil {
		item, err := domain.NewItem(name, *position)
		if err != nil {
			slog.WarnContext(ctx, "NewItem validation failed", "name", name, "position", *position, "error", err)
			return nil, Validation("create item", err)
		}
		result, err := s.repo.Add(ctx, item)
		if err != nil {
			slog.ErrorContext(ctx, "repo.Add failed", "error", err)
			return nil, err
		}
		resultID := result.ID()
		slog.InfoContext(ctx, "item created", "id", resultID.String(), "position", result.Position().Int())
		return domainToAppItem(result, nil), nil
	}

	// Auto-position: create with placeholder, repo will assign real position atomically
	item, err := domain.NewItem(name, 1)
	if err != nil {
		slog.WarnContext(ctx, "NewItem validation failed", "name", name, "error", err)
		return nil, Validation("create item", err)
	}
	result, err := s.repo.AddWithNextPosition(ctx, item)
	if err != nil {
		slog.ErrorContext(ctx, "repo.AddWithNextPosition failed", "error", err)
		return nil, err
	}
	resultID := result.ID()
	slog.InfoContext(ctx, "item created", "id", resultID.String(), "position", result.Position().Int())
	return domainToAppItem(result, nil), nil
}

func (s *ItemService) List(ctx context.Context, query ListQuery) (ListResult, error) {
	filter := domain.ListFilter{
		Done:   query.Done,
		Search: query.Search,
	}
	sortFields := appSortFieldsToDomain(query.SortFields)

	count, err := s.repo.Count(ctx, filter)
	if err != nil {
		return ListResult{}, err
	}
	domainItems, err := s.repo.List(ctx, filter, sortFields, query.Page, query.PerPage)
	if err != nil {
		return ListResult{}, err
	}

	items := make([]Item, 0, len(domainItems))
	for _, d := range domainItems {
		items = append(items, *domainToAppItem(d, query.Fields))
	}
	return ListResult{Items: items, TotalCount: count}, nil
}

func (s *ItemService) Update(ctx context.Context, reqItem *Item) (*Item, error) {
	modelID, err := domain.NewModelID(reqItem.ID)
	if err != nil {
		return nil, Validation("update item", err)
	}
	result, err := s.repo.Update(ctx, modelID, func(item *domain.Item) error {
		if reqItem.Done != nil {
			if *reqItem.Done {
				item.Complete()
			} else {
				item.Uncomplete()
			}
		}
		if reqItem.Position != nil {
			if err := item.MoveTo(*reqItem.Position); err != nil {
				return Validation("update item position", err)
			}
		}
		if reqItem.Name != nil {
			if err := item.Rename(*reqItem.Name); err != nil {
				return Validation("update item name", err)
			}
		}
		return nil
	})
	if err != nil {
		if errors.Is(err, domain.ErrNotFound) {
			return nil, NotFound("update item", err)
		}
		return nil, err
	}
	return domainToAppItem(result, nil), nil
}

