}

func (a *mysqlAdapter) CountItems(ctx context.Context, filter listFilter) (int, error) {
	var conditions []string
	var args []any

	if filter.Done != nil {
		conditions = append(conditions, "done=?")
		args = append(args, *filter.Done)
	}
	if filter.Search != nil && *filter.Search != "" {
		cond, arg := a.searchCondition(*filter.Search)
		conditions = append(conditions, cond)
		args = append(args, arg)
	}

	q := "SELECT COUNT(*) FROM item"
	if len(conditions) > 0 {
		q += " WHERE " + strings.Join(conditions, " AND ")
	}
	var count int
	if err := a.db.QueryRowContext(ctx, q, args...).Scan(&count); err != nil {
		return 0, fmt.Errorf("count items: %w", err)
	}
	return count, nil
}

func (a *mysqlAdapter) searchCondition(search string) (string, any) {
	if a.ftsEnabled {
		return "MATCH(name) AGAINST(? IN BOOLEAN MODE)", buildMySQLFTSQuery(search)
	}
	return "LOWER(name) LIKE LOWER(?)", "%" + search + "%"
}

// buildMySQLFTSQuery converts a user search string into a MySQL FULLTEXT boolean mode query
// with prefix matching and AND logic.
// Example: "buy milk" -> "+buy* +milk*"
func buildMySQLFTSQuery(search string) string {
	words := strings.Fields(search)
	sanitized := make([]string, 0, len(words))
	for _, word := range words {
		word = strings.ReplaceAll(word, "+", "")
		word = strings.ReplaceAll(word, "-", "")
		word = strings.ReplaceAll(word, "*", "")
		if word == "" {
			continue
		}
		sanitized = append(sanitized, "+"+word+"*")
	}
	return strings.Join(sanitized, " ")
}

package ports

import (
	"strings"
	"time"

	"github.com/evgeniy-klemin/todo/internal/item/app"
	"github.com/pkg/errors"
)

func appItemsToRespItems(appItems []app.Item) []ItemResponse {
	var res []ItemResponse
	for _, appItem := range appItems {
		var respCreatedAt *time.Time
		if appItem.CreatedAt != nil {
			createdAt := (*appItem.CreatedAt).UTC()
			respCreatedAt = &createdAt
		}
		res = append(res, ItemResponse{
			Id:        appItem.ID,
			Name:      appItem.Name,
			Position:  appItem.Position,
			Done:      appItem.Done,
			CreatedAt: respCreatedAt,
		})
	}
	return res
}

func appItemToResp(appItem *app.Item) *ItemResponse {
	var respCreatedAt *time.Time
	if appItem.CreatedAt != nil {
		createdAt := (*appItem.CreatedAt).UTC()
		respCreatedAt = &createdAt
	}
	return &ItemResponse{
		Id:        appItem.ID,
		Name:      appItem.Name,
		Position:  appItem.Position,
		Done:      appItem.Done,
		CreatedAt: respCreatedAt,
	}
}

func getAppFieldsFromGetParam(fields *string) ([]app.ItemField, error) {
	var res []app.ItemField
	if fields != nil {
		strFields := strings.Split(*fields, ",")
		if len(strFields) > 0 {
			for _, strField := range strFields {
				var field app.ItemField
				switch strField {
				case "name":
					field = app.ItemFieldName
				case "position":
					field = app.ItemFieldPosition
				case "done":
					field = app.ItemFieldDone
				case "created_at":
					field = app.ItemFieldCreatedAt
				default:
					return nil, errors.Errorf("Field %s not found", strField)
				}
				res = append(res, field)
			}
		}
	}
	if len(res) == 0 {
		res = app.DefaultItemFields
	}
	return res, nil
}

func getSortFieldsFromGetParam(sort *string) (app.SortFields, error) {
	var sortFields app.SortFields
	if sort != nil {
		strFields := strings.Split(*sort, ",")
		if len(strFields) > 0 {
			for _, strField := range strFields {
				sortDirection := app.SortDirectionAsc
				if strings.HasPrefix(strField, "-") {
					sortDirection = app.SortDirectionDesc
					strField = strings.TrimLeft(strField, "-")
				}
				var field app.ItemField
				switch strField {
				case "name":
					field = app.ItemFieldName
				case "position":
					field = app.ItemFieldPosition
				case "done":
					field = app.ItemFieldDone
				case "created_at":
					field = app.ItemFieldCreatedAt
				default:
					return nil, errors.Errorf("Field %s not found", strField)
				}
				sortFields = append(sortFields, app.SortField{
					Field:         field,
					SortDirection: sortDirection,
				})
			}
		}
	}
	return sortFields, nil
}

