	"github.com/evgeniy-klemin/todo/db/fts"
	"github.com/evgeniy-klemin/todo/db/migrations"
	item "github.com/evgeniy-klemin/todo/internal/item"
	itemports "github.com/evgeniy-klemin/todo/internal/item/ports"
)

func registerDoc(e *echo.Echo) {
	assetHandler := http.FileServer(todo.GetFileSystem())
	e.GET("/docs/*", echo.WrapHandler(http.StripPrefix("/docs/", assetHandler)))
	e.Use(func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			if c.Path() == "/" {
				_ = c.Redirect(http.StatusPermanentRedirect, "/docs/")
			}
			return next(c)
		}
	})
}

func setOapiValidator(e *echo.Echo) {
	itemSwagger, err := itemports.GetSwagger()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error loading swagger spec: %s\n", err)
		os.Exit(1)
	}
	itemSwagger.Servers = nil
	e.Use(middleware.OapiRequestValidatorWithOptions(itemSwagger, &middleware.Options{
		Skipper: func(c echo.Context) bool {
			switch c.Path() {
			case "/docs/*", "/":
				return true
			}
			return false
		},
	}))
}

func server(port int) {
	e := echo.New()
	// Log all requests
	e.Use(echomiddleware.Logger())
	// Swagger validation
	setOapiValidator(e)

	drv := os.Getenv("DB_DRIVER")
	if drv == "" {
		drv = driver.SQLite
	}

	dsn := os.Getenv("DB_DSN")
	if dsn == "" {
		switch drv {
		case driver.MySQL:
			dsn = "todo:todo@tcp(localhost)/todotest?parseTime=true"
		default:
			dsn = "file:todotest.db?cache=shared"
		}
	}

	db, err := sql.Open(drv, dsn)
	if err != nil {
		panic(err)
	}
	if err := migrations.Run(db, drv); err != nil {
		panic(err)
	}
	var ftsEnabled bool
	if drv == driver.MySQL {
		ftsEnabled = true // FULLTEXT index created by goose migration 00003
	} else {
		ftsEnabled = fts.Apply(db)
	}
	if !ftsEnabled {
		switch drv {
		case driver.MySQL:
			fmt.Fprintf(os.Stderr, "Warning: MySQL FULLTEXT index not available, falling back to LIKE search\n")
		default:
			fmt.Fprintf(os.Stderr, "Warning: FTS5 not available, falling back to LIKE search\n")
		}
	}

	// Containers
	itemContainer := item.NewContainer(db, drv, ftsEnabled)

	// Register http handlers
	itemContainer.RegisterHandlers(e)

	registerDoc(e)

	e.Logger.Fatal(e.Start(fmt.Sprintf("0.0.0.0:%d", port)))
}

func main() {
	var port = flag.Int("port", 3000, "Port for test HTTP server")
	flag.Parse()

	server(*port)
}

package ports

import (
	"fmt"
	"net/http"
	"strconv"
	"strings"
)

type LinkType int

const (
	LinkTypePrev LinkType = iota + 1
	LinkTypeNext
	LinkTypeFirst
	LinkTypeLast
)

type Link struct {
	req       *http.Request
	paginator *Paginator
}

func (l *Link) Encode(linkType LinkType) string {
	query := l.req.URL.Query()
	var rel string
	switch linkType {
	case LinkTypeNext:
		query.Set("page", strconv.Itoa(l.paginator.Next()))
		rel = "next"
	case LinkTypePrev:
		query.Set("page", strconv.Itoa(l.paginator.Prev()))
		rel = "prev"
	case LinkTypeFirst:
		query.Set("page", strconv.Itoa(l.paginator.First()))
		rel = "first"
	case LinkTypeLast:
		query.Set("page", strconv.Itoa(l.paginator.Last()))
		rel = "last"
	}
	return fmt.Sprintf("<%s?%s>;rel=%s", l.req.URL.Path, query.Encode(), rel)
}

func links(req *http.Request, paginator *Paginator) string {
	links := make([]string, 0)
	link := Link{
		paginator: paginator,
		req:       req,
	}
	if paginator.HasNext() {
		links = append(links, link.Encode(LinkTypeNext))
	}
	if paginator.HasPrev() {
		links = append(links, link.Encode(LinkTypePrev))
	}
	links = append(links, link.Encode(LinkTypeFirst))
	links = append(links, link.Encode(LinkTypeLast))

	return strings.Join(links, ",")
}

package ports

import "math"

type Paginator struct {
	page    int
	perPage int
	count   int
}

func NewPaginator(page, perPage, count int) *Paginator {
	return &Paginator{page, perPage, count}
}

func (p *Paginator) Page() int {
	return p.page
}

func (p *Paginator) PerPage() int {
	return p.perPage
}

func (p *Paginator) Pages() int {
	return int(math.Ceil(float64(p.count) / float64(p.perPage)))
}

func (p *Paginator) Last() int {
	return p.Pages()
}

func (p *Paginator) First() int {
	return 1
}

func (p *Paginator) HasPrev() bool {
	return (p.page - 1) > 0
}

func (p *Paginator) Prev() int {
	return p.page - 1
}

func (p *Paginator) HasNext() bool {
	return (p.page + 1) <= p.Last()
}

func (p *Paginator) Next() int {
	return p.page + 1
}

package fts

import (
	"database/sql"
	_ "embed"
)

//go:embed item_fts.sql
var ftsTable string

//go:embed item_fts_triggers.sql
var ftsTriggers string

//go:embed item_fts_rebuild.sql
var ftsRebuild string

//go:embed item_fts_drop_triggers.sql
var dropTriggers string

// Apply creates the FTS5 virtual table and triggers on db.
// Returns true on success, false if FTS5 is unavailable or setup fails.
// FTS5 unavailability is graceful degradation — the app falls back to LIKE
// search — so none of the errors below are fatal.
func Apply(db *sql.DB) bool {
	if _, err := db.Exec(ftsTable); err != nil {
		// FTS5 not compiled in or table creation failed; clean up any stale
		// triggers. The cleanup error is intentionally ignored: the triggers
		// may not exist yet, which is expected on a fresh database.
		_, _ = db.Exec(dropTriggers)
		return false
	}
	if _, err := db.Exec(ftsTriggers); err != nil {
		return false
	}
	// Rebuild populates the FTS index from existing rows. A failure here is
	// non-fatal: the index will be populated incrementally as rows are
	// inserted/updated via the triggers we just created.
	_, _ = db.Exec(ftsRebuild)
	return true
}

